import { describe, it, expect, beforeEach } from '@jest/globals';
import { validateDashboardConfig, validateApiConfig } from '../src/config/validator';

describe('配置验证系统', () => {
  beforeEach(() => {
    // 重置环境变量
    process.env.DASHBOARD_PORT = '3000';
    process.env.LOG_LEVEL = 'info';
    process.env.ENABLE_METRICS = 'true';
  });

  describe('Dashboard配置', () => {
    it('应该接受有效的端口号', () => {
      process.env.DASHBOARD_PORT = '8080';
      const config = validateDashboardConfig();
      expect(config.port).toBe(8080);
    });

    it('应该拒绝超出范围的端口号', () => {
      process.env.DASHBOARD_PORT = '99999';
      expect(() => validateDashboardConfig()).toThrow('端口号必须 <= 65535');
    });

    it('应该拒绝无效的日志级别', () => {
      process.env.LOG_LEVEL = 'invalid';
      expect(() => validateDashboardConfig()).toThrow('必须是有效的日志级别');
    });

    it('应该正确解析布尔值', () => {
      process.env.ENABLE_METRICS = 'false';
      const config = validateDashboardConfig();
      expect(config.enableMetrics).toBe(false);
    });
  });

  describe('API配置', () => {
    it('应该在Token为空时抛出错误', () => {
      delete process.env.ANTHROPIC_AUTH_TOKEN;
      expect(() => validateApiConfig()).toThrow('ANTHROPIC_AUTH_TOKEN 不能为空');
    });

    it('应该接受有效的Token', () => {
      process.env.ANTHROPIC_AUTH_TOKEN = 'test-token-123';
      const config = validateApiConfig();
      expect(config.anthropicAuthToken).toBe('test-token-123');
    });
  });
});
