### 5. 核心实现

```typescript
// src/config/validator.ts
import { ConfigSchema, AppConfig } from './schema';
import { config } from 'dotenv';

export class ConfigValidator {
  /**
   * 加载并验证配置
   */
  static load(): AppConfig {
    // 1. 加载环境变量
    const env = config();

    // 2. 转换为配置对象
    const rawConfig = this.mapEnvToConfig(env);

    // 3. 验证配置
    const result = ConfigSchema.safeParse(rawConfig);

    if (!result.success) {
      this.formatErrors(result.error);
      process.exit(1);
    }

    return result.data;
  }

  /**
   * 环境变量映射到配置对象
   */
  private static mapEnvToConfig(env: Record<string, string>): Record<string, unknown> {
    return {
      anthropic: {
        authToken: env.ANTHROPIC_AUTH_TOKEN,
        baseUrl: env.ANTHROPIC_BASE_URL,
        maxTokens: Number(env.ANTHROPIC_MAX_TOKENS),
        model: env.ANTHROPIC_MODEL,
      },
      // ... 其他配置
    };
  }

  /**
   * 格式化错误信息
   */
  private static formatErrors(error: z.ZodError): never {
    console.error('\n❌ Configuration Validation Failed\n');

    error.errors.forEach((err) => {
      const path = err.path.join('.');
      console.error(`  • ${path}`);
      console.error(`    Expected: ${err.expected}`);
      console.error(`    Received: ${err.received}`);
      console.error(`    Message: ${err.message}\n`);
    });

    console.error('💡 Run `npm run config:generate` to see all options\n');
    throw error;
  }

  /**
   * 生成配置模板
   */
  static generateTemplate(): string {
    const defaults: Partial<AppConfig> = {
      anthropic: {
        authToken: "your-api-key-here",
        baseUrl: "https://api.anthropic.com",
        maxTokens: 4096,
        model: "claude-3-sonnet-20240229",
      },
      // ... 其他默认值
    };

    return `# AI Dev Team Configuration
# Generated at: ${new Date().toISOString()}

${Object.entries(defaults).map(([key, value]) => {
  return `#${key.toUpperCase()}_${Object.keys(value).join('\n#')}`;
}).join('\n')}`;
  }
}
```

