### 任务2.1: 创建错误处理中间件

**文件**: `src/middleware/error-handler.ts` (新建)

```typescript
import { FastifyRequest, FastifyReply } from 'fastify';
import pino from 'pino';

export class ErrorHandler {
  private logger: pino.Logger;

  constructor(logger: pino.Logger) {
    this.logger = logger;
  }

  handle(error: Error, req: FastifyRequest, reply: FastifyReply) {
    // 1. 记录错误日志
    this.logger.error({
      error: {
        name: error.name,
        message: error.message,
        stack: error.stack,
      },
      request: {
        method: req.method,
        url: req.url,
        headers: req.headers,
      },
    }, 'Request error');

    // 2. 保存到数据库（异步，不阻塞响应）
    this.saveToDatabase(error, req).catch(err => {
      this.logger.error({ err }, 'Failed to save error to database');
    });

    // 3. 返回用户友好的错误响应
    const statusCode = this.getStatusCode(error);
    reply.status(statusCode).send({
      success: false,
      error: {
        message: this.getUserFriendlyMessage(error),
        code: error.name,
        ...(process.env.NODE_ENV === 'development' && {
          stack: error.stack,
        }),
      },
      timestamp: new Date().toISOString(),
    });
  }

  private getStatusCode(error: Error): number {
    // 根据错误类型返回适当的HTTP状态码
    if (error.name === 'ValidationError') return 400;
    if (error.name === 'UnauthorizedError') return 401;
    if (error.name === 'NotFoundError') return 404;
    return 500;
  }

  private getUserFriendlyMessage(error: Error): string {
    const messages: Record<string, string> = {
      'ValidationError': '请求参数验证失败',
      'UnauthorizedError': '未授权访问',
      'NotFoundError': '请求的资源不存在',
      'DatabaseError': '数据库操作失败',
    };

    return messages[error.name] || '服务器内部错误，请稍后重试';
  }

  private async saveToDatabase(error: Error, req: FastifyRequest) {
    // TODO: 实现错误日志持久化
  }
}

// 导出中间件函数
export function createErrorHandler(logger: pino.Logger) {
  const handler = new ErrorHandler(logger);
  return (error: Error, req: FastifyRequest, reply: FastifyReply) => {
    handler.handle(error, req, reply);
  };
}
