### 任务3.1: 全局错误捕获

**文件**: `dashboard/src/utils/error-handler.ts` (新建)

```typescript
import { ElNotification } from 'element-plus';

export class AppErrorHandler {
  private static instance: AppErrorHandler;

  private constructor() {
    this.setupGlobalHandlers();
  }

  static getInstance() {
    if (!this.instance) {
      this.instance = new AppErrorHandler();
    }
    return this.instance;
  }

  private setupGlobalHandlers() {
    // Vue错误捕获
    app.config.errorHandler = (err, instance, info) => {
      this.handleError(err, 'Vue', { info });
    };

    // 未捕获的Promise错误
    window.addEventListener('unhandledrejection', (event) => {
      this.handleError(event.reason, 'UnhandledPromise');
    });

    // 全局错误
    window.addEventListener('error', (event) => {
      this.handleError(event.error, 'Global', {
        message: event.message,
        filename: event.filename,
        line: event.lineno,
      });
    });
  }

  handleError(error: Error, source: string, context?: any) {
    console.error(`[${source}]`, error);

    // 显示用户友好的通知
    ElNotification({
      title: '发生错误',
      message: this.getUserMessage(error),
      type: 'error',
      duration: 5000,
    });

    // 发送到后端（生产环境）
    if (import.meta.env.PROD) {
      this.reportToServer(error, source, context);
    }
  }

  private getUserMessage(error: Error): string {
    const messages: Record<string, string> = {
      'NetworkError': '网络连接失败，请检查网络设置',
      'ValidationError': '提交的数据验证失败',
      'UnauthorizedError': '登录已过期，请重新登录',
    };

    return messages[error.name] || error.message || '未知错误';
  }

  private async reportToServer(error: Error, source: string, context?: any) {
    try {
      await fetch('/api/errors', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: error.name,
          message: error.message,
          stack: error.stack,
          source,
          context,
          timestamp: new Date().toISOString(),
        }),
      });
    } catch (err) {
      console.error('Failed to report error:', err);
    }
  }
}

// 在main.ts中初始化
export function setupErrorHandling() {
  AppErrorHandler.getInstance();
}
```

### 任务3.2: API错误拦截器

**文件**: `dashboard/src/api/error-interceptor.ts` (修改)

```typescript
import axios from 'axios';
import { ElNotification } from 'element-plus';

const apiClient = axios.create({
  baseURL: import.meta.env.VITE_API_URL || 'http://localhost:3000/api',
  timeout: 10000,
});

// 响应拦截器
apiClient.interceptors.response.use(
  response => response.data,
  error => {
    // 处理不同类型的错误
    if (error.response) {
      // 服务器返回错误响应
      const { status, data } = error.response;

      switch (status) {
        case 400:
          ElNotification({
            title: '请求错误',
            message: data.error?.message || '请求参数不正确',
            type: 'error',
          });
          break;
        case 401:
          ElNotification({
            title: '未授权',
            message: '请先登录',
            type: 'warning',
          });
          // 跳转到登录页
          break;
        case 500:
          ElNotification({
            title: '服务器错误',
            message: '服务器发生错误，请稍后重试',
            type: 'error',
          });
          break;
        default:
          ElNotification({
            title: '错误',
            message: data.error?.message || '请求失败',
            type: 'error',
          });
      }
    } else if (error.request) {
      // 请求发送但无响应
      ElNotification({
        title: '网络错误',
        message: '无法连接到服务器，请检查网络',
        type: 'error',
      });
    } else {
      // 其他错误
      ElNotification({
        title: '错误',
        message: error.message,
        type: 'error',
      });
    }

    return Promise.reject(error);
  }
);

export default apiClient;
```

